def calculate_tip(bill, tip_pct):
    """Return the tip amount based on bill and tip percentage."""
    return round(bill * tip_pct / 100, 2)


def split_bill(total, people):
    """Return each person's share of the total bill."""
    return round(total / people, 2)


def calculate_total(bill, tip_pct, tax_pct):
    """Return the total bill including tip and tax."""
    tip = bill * tip_pct / 100
    tax = bill * tax_pct / 100
    return round(bill + tip + tax, 2)


def format_currency(amount):
    """Return amount formatted as '$X.XX' string."""
    return f"${amount:.2f}"
